INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", -470.0, 1.47, 126401, 1, "クローチェ", 10001, 0.0, "2023/06/30 12:00:00", 2002, 2, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", -470.0, 2.15, 126401, 2, "クローチェ", 10002, 0.0, "2023/06/30 12:00:00", 2002, 1, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", -470.0, 0.0, 126501, 1, "ライラエル", 10003, 0.0, "2023/06/30 12:00:00", 2002, 2, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", -470.0, 0.0, 126501, 2, "ライラエル", 10004, 0.0, "2023/06/30 12:00:00", 2002, 1, "2023/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", -470.0, 0.0, 127702, 1, "リンド", 10005, 0.0, "2023/09/15 15:00:00", 2002, 2, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", -470.0, 0.0, 127702, 2, "リンド", 10006, 0.0, "2023/09/15 15:00:00", 2002, 2, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 2, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", -470.0, 0.0, 127802, 1, "ヴルム", 10007, 0.0, "2023/09/15 15:00:00", 2002, 1, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", -470.0, 6.5, 127802, 2, "ヴルム", 10008, 0.0, "2023/09/15 15:00:00", 2002, 1, "2023/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 3, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", -470.0, 0.0, 129602, 1, "アネモネ", 10009, 0.0, "2023/12/15 15:00:00", 2002, 1, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 3, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", -470.0, 0.0, 129602, 2, "アネモネ", 10010, 0.0, "2023/12/15 15:00:00", 2002, 1, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 3, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", -470.0, 0.0, 129701, 1, "ネフィ=ネラ", 10011, 0.0, "2023/12/15 15:00:00", 2002, 1, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 3, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", -470.0, 6.2, 129701, 2, "ネフィ=ネラ", 10012, 0.0, "2023/12/15 15:00:00", 2002, 1, "2024/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 4, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", -470.0, 3.1, 130301, 1, "カノン", 10013, 0.0, "2024/03/15 15:00:00", 2002, 5, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 4, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", -470.0, 6.15, 130301, 2, "カノン", 10014, 0.0, "2024/03/15 15:00:00", 2002, 2, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 4, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", -470.0, 0.0, 130401, 1, "ナーナ", 10015, 0.0, "2024/03/15 15:00:00", 2002, 2, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 4, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", -470.0, 3.35, 130401, 2, "ナーナ", 10016, 0.0, "2024/03/15 15:00:00", 2002, 1, "2024/06/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 5, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", -470.0, 0.0, 130502, 1, "ホウオウ", 10017, 0.0, "2024/06/15 15:00:00", 2002, 1, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 5, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", -470.0, 3.18, 130502, 2, "ホウオウ", 10018, 0.0, "2024/06/15 15:00:00", 2002, 1, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 5, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", -470.0, 0.0, 130503, 3, "ホウオウ", 10019, 0.0, "2024/06/15 15:00:00", 2002, 4, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 5, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", -470.0, 4.9, 123301, 1, "ネア", 10020, 0.0, "2024/06/15 15:00:00", 2002, 2, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 5, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", -470.0, 4.8, 123301, 2, "ネア", 10021, 0.0, "2024/06/15 15:00:00", 2002, 2, "2024/09/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 6, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", -470.0, 4.922, 133301, 1, "カリザ", 10022, 0.0, "2024/09/15 15:00:00", 2002, 1, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 6, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", -470.0, 9.638, 133301, 2, "カリザ", 10023, 0.0, "2024/09/15 15:00:00", 2002, 5, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 6, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", -470.0, 2.88, 133401, 1, "ミーア", 10024, 0.0, "2024/09/15 15:00:00", 2002, 2, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 6, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", -470.0, 4.818, 133401, 2, "ミーア", 10025, 0.0, "2024/09/15 15:00:00", 2002, 1, "2024/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 7, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", -470.0, 1.78, 133002, 1, "グレイス", 10026, 0.0, "2024/12/15 15:00:00", 2002, 1, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", -470.0, 6.15, 133002, 2, "グレイス", 10027, 0.0, "2024/12/15 15:00:00", 2002, 7, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (6, 7, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", -470.0, 4.28, 133102, 1, "ヴァイオレット", 10028, 0.0, "2024/12/15 15:00:00", 2002, 2, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 7, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", -470.0, 0.0, 133102, 2, "ヴァイオレット", 10029, 0.0, "2024/12/15 15:00:00", 2002, 1, "2025/03/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 8, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", -470.0, 5.53, 136902, 1, "ルルィ", 10030, 0.0, "2025/03/15 15:00:00", 2002, 1, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (9, 8, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", -470.0, 6.05, 136902, 2, "ルルィ", 10031, 0.0, "2025/03/15 15:00:00", 2002, 7, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 8, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", -470.0, 0.0, 137001, 1, "デュラン", 10032, 0.0, "2025/03/15 15:00:00", 2002, 1, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 8, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", -470.0, 0.0, 137001, 2, "デュラン", 10033, 0.0, "2025/03/15 15:00:00", 2002, 1, "2025/06/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 9, "おう\n好きなもん持ってきな", -470.0, 0.0, 135902, 1, "サツキ", 10034, 0.0, "2025/06/16 15:00:00", 2002, 2, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 9, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", -470.0, 4.935, 135902, 2, "サツキ", 10035, 0.0, "2025/06/16 15:00:00", 2002, 6, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 9, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", -470.0, 7.441, 135802, 1, "ユキノ", 10036, 0.0, "2025/06/16 15:00:00", 2002, 5, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 9, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", -470.0, 0.0, 135802, 2, "ユキノ", 10037, 0.0, "2025/06/16 15:00:00", 2002, 7, "2025/09/23 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 10, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", -470.0, 2.295, 130901, 1, "クルル", 10038, 0.0, "2025/09/16 15:00:00", 2002, 2, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 10, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", -470.0, 6.281, 130901, 2, "クルル", 10039, 0.0, "2025/09/16 15:00:00", 2002, 6, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 10, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", -470.0, 5.549, 137701, 1, "ヴォルガーノ", 10040, 0.0, "2025/09/16 15:00:00", 2002, 1, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (3, 10, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", -470.0, 2.64, 137701, 2, "ヴォルガーノ", 10041, 0.0, "2025/09/16 15:00:00", 2002, 6, "2025/12/22 14:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (7, 11, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", -470.0, 7.642, 132801, 1, "ライラエル", 10042, 0.0, "2025/12/15 15:00:00", 2002, 4, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 11, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", -470.0, 0.0, 132802, 2, "ライラエル", 10043, 0.0, "2025/12/15 15:00:00", 2002, 1, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 11, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", -470.0, 0.0, 134502, 1, "クローチェ", 10044, 0.0, "2025/12/15 15:00:00", 2002, 1, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 11, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", -470.0, 3.72, 134501, 2, "クローチェ", 10045, 0.0, "2025/12/15 15:00:00", 2002, 1, "2026/03/23 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (2, 12, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", -470.0, 4.991, 138201, 1, "ネフィ＝ネラ", 10046, 0.0, "2026/03/16 12:00:00", 2002, 1, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (1, 12, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", -470.0, 3.877, 138201, 2, "ネフィ＝ネラ", 10047, 0.0, "2026/03/16 12:00:00", 2002, 4, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (4, 12, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", -470.0, 1.71, 136001, 1, "アラクネ", 10048, 0.0, "2026/03/16 12:00:00", 2002, 6, "2026/06/22 11:59:59");
INSERT INTO `v1_5a6ab69fa15ba14b6aba98b3c1f5613f9c0f02b1a038a006162b52b0d121954e` VALUES (5, 12, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", -470.0, 5.32, 136001, 2, "アラクネ", 10049, 0.0, "2026/03/16 12:00:00", 2002, 2, "2026/06/22 11:59:59");
